from math import isqrt

def solve():
    input_data = sys.stdin.buffer.read().split()
    n = int(input_data[0])
    a = [int(x) for x in input_data[1:n+1]]

    MOD = 10**9 + 7
    MAX = 10**5 + 1

    # Compute phi
    phi = list(range(MAX))
    for i in range(2, MAX):
        if phi[i] == i:  # i is prime
            for j in range(i, MAX, i):
                phi[j] -= phi[j] // i

    # Precompute divisors of each a[i]
    def get_divisors(x):
        divs = []
        for d in range(1, isqrt(x)+1):
            if x % d == 0:
                divs.append(d)
                if d != x // d:
                    divs.append(x // d)
        return divs

    ans = 0

    from collections import defaultdict

    for d2 in range(1, n+1):
        f = defaultdict(int)
        for idx in range(d2, n+1, d2):
            ai = a[idx-1]
            for d1 in get_divisors(ai):
                f[d1] += 1
        phi_d2 = phi[d2]
        for d1, cnt in f.items():
            ans = (ans + phi[d1] * phi_d2 % MOD * (cnt * cnt % MOD)) % MOD

    print(ans)

solve()

